const Misc = {
	bresenhamLine(x0, y0, x1, y1, cb) {
		let dx = Math.abs(x1 - x0),
			dy = Math.abs(y1 - y0),
			sx = (x0 < x1) ? 1 : -1,
			sy = (y0 < y1) ? 1 : -1,
			err = dx - dy;
		while(true) {
			if (cb) cb(x0, y0);
			if (x0 === x1 && y0 === y1) break;
			let e2 = 2 * err;
			if (e2 > -dy) { err -= dy; x0 += sx; }
			if (e2 < dx) { err += dx; y0 += sy; }
		}
	},
	createCanvas(width, height) {
		let cvs = $(document.createElement("canvas")),
			ctx = cvs[0].getContext("2d", { willReadFrequently: true });
		cvs.prop({ width, height });
		return { cvs, ctx }
	},
	generateSpectrum(scale) {
		let spectrum = [];
		scale.map(g => {
			switch (g.constructor) {
				case Array:
					for (var i=g[0]; i<g[1]; i+=g[2]) {
						if (spectrum.at(-1) !== i) spectrum.push(i);
					}
					if (spectrum.at(-1) !== g[1]) spectrum.push(g[1]);
					break;
				default:
					if (spectrum.at(-1) !== g) spectrum.push(g);
			}
		});
		return spectrum;
	},
	scaleRectTo(rect, maxSize) {
		let tW, tH;
		if (rect.m > rect.n) {
			tW = maxSize;
			tH = Math.floor(maxSize * (rect.n / rect.m));
		} else {
			tW = Math.floor(maxSize * (rect.m / rect.n));
			tH = maxSize;
		}
		return new Point2D(tW, tH);
	},
	fitWithin(w, h, mW, mH) {
		let scale = Math.min(mW/w, mH/h, 1);
		return {
			width: Math.round(w * scale),
			height: Math.round(h * scale),
		};
	},
	findBoundingBox(ctx) {
		let _min = Math.min,
			_max = Math.max,
			w = ctx.canvas.width,
			h = ctx.canvas.height,
			d = ctx.getImageData(0, 0, w, h).data,
			min = {
				x: w,
				y: h,
			},
			max = {
				x: 0,
				y: 0,
			};
		for (let y=0; y<h; y++) {
			for (let x=0; x<w; x++) {
				if (d[y*w*4 + x*4+3]) {
					min.x = _min(min.x, x);
					max.x = _max(max.x, x);
					min.y = _min(min.y, y);
					max.y = y;
					x = max.x;
				}
			}
		}
		return {
			x: min.x,
			y: min.y,
			w: max.x - min.x,
			h: max.y - min.y,
		};
	}
};

const Tween = {
	linear(t, b, c, d) {
		return c * t / d + b;
	},
	bounce(t, b, c, d) {
		return c * Math.sin(t / d * Math.PI) + b;
	},
	easeIn(t, b, c, d) {
		return c * (t /= d) * t * t + b;
	},
	easeOut(t, b, c, d) {
		return c * ((t = t / d - 1) * t * t + 1) + b;
	},
	easeInOut(t, b, c, d) {
		return ((t /= d / 2) < 1) ? c / 2 * t * t * t + b : c / 2 * ((t -= 2) * t * t + 2) + b;
	},
};


