PixelUtil.rgbaToGrayPlane = function(l, d, G) {
	var b = l.length,
		V = .3,
		Q = .59,
		t = .11;
	if (G) {
		V = G[0];
		Q = G[1];
		t = G[2];
	}
	for (var A = 0; A < b; A += 4) d[A >> 2] = ~~(l[A + 0] * V + l[A + 1] * Q + l[A + 2] * t + .5);
};

PixelUtil.grayPlaneToRgbaChannels = function(l, d) {
	var G = d.length;
	for (var A = 0; A < G; A += 4) {
		var b = l[A >>> 2];
		d[A] = b;
		d[A + 1] = b;
		d[A + 2] = b;
	}
};

PixelUtil.channelPlanesToRgba = function(l, d) {
	var G = l.aS,
		b = l.o,
		V = l.J,
		Q = l.k,
		t = Math.min(l.aS.length, d.buffer.byteLength >>> 2),
		I = 4 * Math.floor(t / 4),
		y = new Uint32Array(d.buffer),
		e = new Uint32Array(G.buffer),
		M = new Uint32Array(b.buffer),
		R = new Uint32Array(V.buffer),
		J = new Uint32Array(Q.buffer);
	for (var A = 0; A < I; A += 4) {
		var n = e[A >> 2],
			r = J[A >> 2],
			T = R[A >> 2],
			j = M[A >> 2];
		y[A] = n << 24 | (r & 255) << 16 | (T & 255) << 8 | j & 255;
		y[A + 1] = (n & 65280) << 16 | (r & 65280) << 8 | T & 65280 | (j & 65280) >>> 8;
		y[A + 2] = (n & 16711680) << 8 | r & 16711680 | (T & 16711680) >>> 8 | (j & 16711680) >>> 16;
		y[A + 3] = n & 4278190080 | (r & 4278190080) >>> 8 | (T & 4278190080) >>> 16 | (j & 4278190080) >>> 24;
	}
	for (var A = I; A < t; A++) y[A] = G[A] << 24 | Q[A] << 16 | V[A] << 8 | b[A];
};

