					B = (T >>> 16 & 255) * k + (j >>> 16 & 255) * F + (g >>> 16 & 255) * D + (Y >>> 16 & 255) * q,
					a = 1 / H;
				W = ~~(W * a + .5);
				Z = ~~(Z * a + .5);
				B = ~~(B * a + .5);
