	var Q = d.wD(b);
	if (V) Q = Q.wD(V);
	var t = Math.max(0, Q.x - d.x),
		I = Math.max(0, Q.x - b.x),
		y = Math.max(0, Q.y - d.y),
		e = Math.max(0, Q.y - b.y),
		M = Q.m,
		R = Q.n;
	for (var A = 0; A < R; A++) {
		var J = (y + A) * d.m + t,
			n = (e + A) * b.m + I;
		G.set(new Uint8Array(l.buffer, J, M), n);
	}
