PixelUtil.path.shapes.polyline = function(l, d, G, b, V, Q, t) {
	var I = Math.sqrt((b - d) * (b - d) + (V - G) * (V - G)),
		y;
	Q /= 2;
	if (l == 0) y = [-Q, 0, Q, 0, Q, I, -Q, I];
	if (l == 1) {
		var e = Q * 2 * t * 1.3 / 1.5,
			M = Q * t;
		y = [-Q, 0, Q, 0, Q, I - e, M, I - e, 0, I, -M, I - e, -Q, I - e];
	}
	if (l == 2) {
		var e = t[3],
			M = t[2] / 2,
			R = e * (2 / 3) * t[4] / 100,
			J = e - R,
			n = e;
		y = [];
		if (t[0]) y.push(-Q, J, -M, n, 0, 0, M, n, Q, J);
		else y.push(-Q, 0, Q, 0);
		if (t[1]) y.push(Q, I - J, M, I - n, 0, I, -M, I - n, -Q, I - J);
		else y.push(Q, I, -Q, I);
	}
	var r = new Matrix2D(1, 0, 0, 1, 0, 0);
	r.rotate(Math.atan2(-V + G, b - d) + Math.PI / 2);
	r.translate(d, G);
	PixelUtil.vec.transformCoords(y, r, y);
	return PixelUtil.path.shapes.fromFlatCoords(y, 0)
};

PixelUtil.path.shapes.ellipse = function(l, d, G, b) {
	var V = [{
			type: 6
		}, {
			type: 8,
			all: 0
		}],
		R = .553;
	V.push({
		type: 0,
		H$: 1,
		length: 4,
		c_: 0,
		jt: 0,
		_M: 1
	});
	var Q = l,
		t = d,
		I = l + G,
		y = d + b,
		l = (Q + I) / 2,
		d = (t + y) / 2,
		e = (Q - I) / 2,
		M = (t - y) / 2;
	V.push({
		type: 1,
		Wf: new Point2D(l - R * e, d - M),
		H: new Point2D(l, d - M),
		UU: new Point2D(l + R * e, d - M)
	});
	V.push({
		type: 1,
		Wf: new Point2D(l + e, d - R * M),
		H: new Point2D(l + e, d),
		UU: new Point2D(l + e, d + R * M)
	});
	V.push({
		type: 1,
		Wf: new Point2D(l + R * e, d + M),
		H: new Point2D(l, d + M),
		UU: new Point2D(l - R * e, d + M)
	});
	V.push({
		type: 1,
		Wf: new Point2D(l - e, d + R * M),
		H: new Point2D(l - e, d),
		UU: new Point2D(l - e, d - R * M)
	});
	return V
};

PixelUtil.path.shapes.ellipseArc = function(l, d, G, b, V) {
	var Q = [{
		type: 6
	}, {
		type: 8,
		all: 0
	}];
	Q.push({
		type: 3,
		H$: 1,
		length: 5,
		c_: 0,
		jt: 0,
		_M: 1
	});
	var t = (V - b) / 4;
	for (var A = 0; A < 5; A++) {
		var I = A * t,
			y = Math.cos(I),
			e = Math.sin(I),
			M = .553 * (t / (Math.PI / 2)),
			R = e * M,
			J = -y * M,
			n = new Point2D(y, e);
		Q.push({
			type: 4,
			Wf: A == 0 ? n.clone() : new Point2D(y + R, e + J),
			H: n,
			UU: A == 4 ? n.clone() : new Point2D(y - R, e - J)
		});
	}
	var r = new Matrix2D;
	r.rotate(-b);
	r.scale(G, G);
	r.translate(l, d);
	PixelUtil.path.transformFlatCoords(Q, r);
	return Q
};

